import{_ as a}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as l,c as n,f as o,q as e,D as r,N as d,g as s}from"./chunks/runtime-core.esm-bundler.DuRo-bNR.js";const m=JSON.parse('{"title":"为什么不能直接访问服务器文件路径（/var/www），必须使用 Nginx？","description":"","frontmatter":{},"headers":[],"relativePath":"column/Aliyun/核心概念/为什么前端项目部署需要nginx.md","filePath":"column/Aliyun/核心概念/为什么前端项目部署需要nginx.md","lastUpdated":1779946316000}'),p={name:"column/Aliyun/核心概念/为什么前端项目部署需要nginx.md"};function c(h,t,x,u,g,w){const i=l("ArticleMetadata");return o(),n("div",null,[t[0]||(t[0]=e("h1",{id:"为什么不能直接访问服务器文件路径-var-www-必须使用-nginx",tabindex:"-1"},[s("为什么不能直接访问服务器文件路径（/var/www），必须使用 Nginx？ "),e("a",{class:"header-anchor",href:"#为什么不能直接访问服务器文件路径-var-www-必须使用-nginx","aria-label":'Permalink to "为什么不能直接访问服务器文件路径（/var/www），必须使用 Nginx？"'},"​")],-1)),r(i),t[1]||(t[1]=d('<p>在前端部署到 Linux 服务器（如 ECS）时，很多开发者都会产生一个疑问：</p><p>为什么不能直接通过 <a href="http://IP/var/www/" target="_blank" rel="noreferrer">http://IP/var/www/</a>... 访问打包后的前端项目？ 明明文件就在服务器上，为什么还需要 Nginx？</p><h2 id="一、文件路径-vs-http-url" tabindex="-1">一、文件路径 vs HTTP URL <a class="header-anchor" href="#一、文件路径-vs-http-url" aria-label="Permalink to &quot;一、文件路径 vs HTTP URL&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>47.xx.xx.xx/var/www/react-admin/build/index.html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><p>这是服务器上的 <strong>文件系统路径</strong>，不是 HTTP 地址。这是服务器上的 文件系统路径（Filesystem Path），属于操作系统层面。</p></li><li><p>浏览器只能通过 HTTP 请求访问 <strong>服务器上暴露的端口和路径</strong>，比如 <code>http://47.xx.xx.xx/</code> 或 <code>http://47.xx.xx.xx/admin/</code>。</p></li><li><p>浏览器并不会去服务器文件系统里找 <code>/var/www/...</code> 文件，除非你用 <strong>本地文件协议</strong>（<code>file:///</code>），而这种方式：</p><ul><li>不支持路由刷新（SPA 会 404）</li><li>不支持跨浏览器资源加载</li><li>安全性极差</li></ul></li></ul><blockquote><p>浏览器无法直接访问服务器文件系统, 但是可以通过 HTTP 请求访问服务器上暴露的端口和路径。</p></blockquote><h2 id="二、http-服务器的作用" tabindex="-1">二、HTTP 服务器的作用 <a class="header-anchor" href="#二、http-服务器的作用" aria-label="Permalink to &quot;二、HTTP 服务器的作用&quot;">​</a></h2><p>Nginx（或 Apache、Caddy）是 HTTP 服务器，它做了几个关键工作：</p><ol><li><p><strong>端口监听</strong>：默认监听 80（HTTP）或者 443（HTTPS）端口</p></li><li><p><strong>路径映射</strong>：把 <code>http://47.xx.xx.xx/</code> 请求映射到服务器上的某个目录，例如 <code>/var/www/react-admin/build</code></p></li><li><p><strong>静态资源处理</strong>：</p><ul><li>返回 HTML/CSS/JS 文件</li><li>设置缓存、压缩（gzip）</li><li>支持 SPA 前端路由：<code>try_files $uri /index.html;</code></li></ul></li><li><p><strong>反向代理</strong>（Next.js、Node 服务）：把请求转发到内部 Node 服务，而不是暴露端口给外网</p></li></ol><p>简单说：</p><blockquote><p>HTTP 浏览器请求的路径必须由 HTTP 服务器去解析和映射到服务器文件系统，而不是直接访问文件路径。</p></blockquote><h2 id="三、如果不用-nginx-会发生什么" tabindex="-1">三、如果不用 Nginx，会发生什么 <a class="header-anchor" href="#三、如果不用-nginx-会发生什么" aria-label="Permalink to &quot;三、如果不用 Nginx，会发生什么&quot;">​</a></h2><p>假设你直接访问：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://47.xx.xx.xx/var/www/react-admin/build/index.html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><p>没有 HTTP 服务器在监听 <code>/var/www/...</code>，所以浏览器会报 <strong>404 或连接失败</strong></p></li><li><p>即使你改成 <code>file:///var/www/...</code> 打开：</p><ul><li>只能本地打开</li><li>SPA 刷新路由会 404</li><li>不能通过网络分享</li></ul></li></ul><h2 id="四、为什么必须用-nginx-或任何-http-服务" tabindex="-1">四、为什么必须用 Nginx（或任何 HTTP 服务） <a class="header-anchor" href="#四、为什么必须用-nginx-或任何-http-服务" aria-label="Permalink to &quot;四、为什么必须用 Nginx（或任何 HTTP 服务）&quot;">​</a></h2><ol><li><p><strong>提供 HTTP 协议支持</strong> 浏览器只能通过 HTTP/HTTPS 请求资源，Nginx 就是这个“协议翻译器”。</p></li><li><p><strong>映射 URL → 文件系统</strong> 你可以把 <code>/</code> 映射到 <code>/var/www/react-admin/build</code>，浏览器访问 <code>/index.html</code> 就能返回正确文件。</p></li><li><p><strong>支持 SPA 路由</strong> React/Vue 的前端路由不是文件系统真实路径，需要 Nginx 的 <code>try_files</code> 或 <code>fallback</code> 机制。</p></li><li><p><strong>性能优化</strong></p><ul><li>gzip 压缩</li><li>缓存策略</li><li>静态文件直接送客户端</li></ul></li><li><p><strong>安全</strong></p><ul><li>避免暴露整个服务器目录</li><li>只能访问指定目录</li></ul></li></ol><h3 id="🔑-小结" tabindex="-1">🔑 小结 <a class="header-anchor" href="#🔑-小结" aria-label="Permalink to &quot;🔑 小结&quot;">​</a></h3><table tabindex="0"><thead><tr><th>直接访问 <code>/var/www/...</code></th><th>通过 Nginx 访问</th></tr></thead><tbody><tr><td>不被浏览器识别 HTTP 路径</td><td>浏览器可以访问 URL</td></tr><tr><td>SPA 刷新会 404</td><td><code>try_files</code> 支持 SPA 路由</td></tr><tr><td>不支持压缩、缓存</td><td>支持 gzip + Cache-Control</td></tr><tr><td>需要暴露整个服务器目录</td><td>安全可控，只暴露 build/dist</td></tr></tbody></table>',19))])}const P=a(p,[["render",c]]);export{m as __pageData,P as default};
